using ContosoUniversity.Models;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using System;

namespace ContosoUniversity.Tests.Models;

[TestClass]
public sealed class PersonTests
{
    [TestMethod]
    public void FullName_ReturnsLastNameCommaFirstName()
    {
        // Arrange
        var student = new Student { LastName = "Alexander", FirstMidName = "Carson" };

        // Act
        var result = student.FullName;

        // Assert
        Assert.AreEqual("Alexander, Carson", result);
    }

    [TestMethod]
    public void FullName_ForInstructor_ReturnsLastNameCommaFirstName()
    {
        // Arrange
        var instructor = new Instructor { LastName = "Smith", FirstMidName = "John" };

        // Act
        var result = instructor.FullName;

        // Assert
        Assert.AreEqual("Smith, John", result);
    }

    [TestMethod]
    public void Student_InheritsFromPerson()
    {
        // Arrange & Act
        var student = new Student();

        // Assert
        Assert.IsInstanceOfType<Person>(student);
    }

    [TestMethod]
    public void Instructor_InheritsFromPerson()
    {
        // Arrange & Act
        var instructor = new Instructor();

        // Assert
        Assert.IsInstanceOfType<Person>(instructor);
    }

    [TestMethod]
    public void Student_HasEnrollmentDate()
    {
        // Arrange
        var date = new DateTime(2020, 9, 1);

        // Act
        var student = new Student { EnrollmentDate = date };

        // Assert
        Assert.AreEqual(date, student.EnrollmentDate);
    }

    [TestMethod]
    public void Instructor_HasHireDate()
    {
        // Arrange
        var date = new DateTime(2000, 3, 15);

        // Act
        var instructor = new Instructor { HireDate = date };

        // Assert
        Assert.AreEqual(date, instructor.HireDate);
    }

    [TestMethod]
    public void Person_ID_CanBeSetAndRead()
    {
        // Arrange & Act
        var student = new Student { ID = 42 };

        // Assert
        Assert.AreEqual(42, student.ID);
    }
}

