using ContosoUniversity.Services;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using System;

namespace ContosoUniversity.Tests.Services;

[TestClass]
public sealed class NotificationServiceTests
{
    private NotificationService _service;

    [TestInitialize]
    public void TestInit()
    {
        // Drain the static queue to avoid cross-test pollution
        TestHelpers.DrainNotificationQueue();
        _service = new NotificationService();
    }

    [TestCleanup]
    public void TestCleanup()
    {
        _service?.Dispose();
    }

    [TestMethod]
    public void SendNotification_AndReceive_ReturnsNotification()
    {
        // Act
        _service.SendNotification("Student", "1", "John Smith", EntityOperation.CREATE, "Admin");
        var result = _service.ReceiveNotification();

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Student", result.EntityType);
        Assert.AreEqual("1", result.EntityId);
        Assert.AreEqual("CREATE", result.Operation);
        Assert.AreEqual("Admin", result.CreatedBy);
        Assert.IsFalse(result.IsRead);
    }

    [TestMethod]
    public void SendNotification_WithDisplayName_SetsCorrectMessage()
    {
        // Act
        _service.SendNotification("Student", "42", "John Smith", EntityOperation.CREATE, "TestUser");
        var result = _service.ReceiveNotification();

        // Assert
        Assert.AreEqual("New Student 'John Smith' has been created", result.Message);
    }

    [TestMethod]
    public void SendNotification_WithoutDisplayName_UsesIdInMessage()
    {
        // Act
        _service.SendNotification("Student", "42", null, EntityOperation.CREATE, "TestUser");
        var result = _service.ReceiveNotification();

        // Assert
        Assert.AreEqual("New Student (ID: 42) has been created", result.Message);
    }

    [TestMethod]
    public void SendNotification_Update_CorrectMessage()
    {
        // Act
        _service.SendNotification("Course", "1050", "Chemistry", EntityOperation.UPDATE, "Admin");
        var result = _service.ReceiveNotification();

        // Assert
        Assert.AreEqual("Course 'Chemistry' has been updated", result.Message);
    }

    [TestMethod]
    public void SendNotification_Delete_CorrectMessage()
    {
        // Act
        _service.SendNotification("Department", "3", "Engineering", EntityOperation.DELETE, "Admin");
        var result = _service.ReceiveNotification();

        // Assert
        Assert.AreEqual("Department 'Engineering' has been deleted", result.Message);
    }

    [TestMethod]
    public void SendNotification_DeleteWithoutDisplayName_CorrectMessage()
    {
        // Act
        _service.SendNotification("Department", "3", null, EntityOperation.DELETE, "Admin");
        var result = _service.ReceiveNotification();

        // Assert
        Assert.AreEqual("Department (ID: 3) has been deleted", result.Message);
    }

    [TestMethod]
    public void ReceiveNotification_EmptyQueue_ReturnsNull()
    {
        // Act
        var result = _service.ReceiveNotification();

        // Assert
        Assert.IsNull(result);
    }

    [TestMethod]
    public void SendNotification_SetsCreatedAt()
    {
        // Arrange
        var before = DateTime.Now;

        // Act
        _service.SendNotification("Student", "1", EntityOperation.CREATE, "Admin");
        var result = _service.ReceiveNotification();

        // Assert
        var after = DateTime.Now;
        Assert.IsNotNull(result);
        Assert.IsTrue(result.CreatedAt >= before && result.CreatedAt <= after);
    }

    [TestMethod]
    public void SendNotification_DefaultUserName_SetsSystem()
    {
        // Act
        _service.SendNotification("Student", "1", EntityOperation.CREATE);
        var result = _service.ReceiveNotification();

        // Assert
        Assert.AreEqual("System", result.CreatedBy);
    }

    [TestMethod]
    public void SendNotification_OverloadWithoutDisplayName_Works()
    {
        // Act
        _service.SendNotification("Student", "1", EntityOperation.UPDATE, "Admin");
        var result = _service.ReceiveNotification();

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Student (ID: 1) has been updated", result.Message);
        Assert.AreEqual("UPDATE", result.Operation);
    }

    [TestMethod]
    public void MarkAsRead_DoesNotThrow()
    {
        // Act & Assert - no exception
        _service.MarkAsRead(1);
        _service.MarkAsRead(999);
    }

    [TestMethod]
    public void Dispose_DoesNotThrow()
    {
        // Act & Assert - no exception
        var service = new NotificationService();
        service.Dispose();
    }

    [TestMethod]
    public void SendNotification_MultipleMessages_ReceiveInOrder()
    {
        // Act
        _service.SendNotification("A", "1", "First", EntityOperation.CREATE, "Admin");
        _service.SendNotification("B", "2", "Second", EntityOperation.UPDATE, "Admin");
        _service.SendNotification("C", "3", "Third", EntityOperation.DELETE, "Admin");

        var first = _service.ReceiveNotification();
        var second = _service.ReceiveNotification();
        var third = _service.ReceiveNotification();

        // Assert
        Assert.AreEqual("A", first.EntityType);
        Assert.AreEqual("B", second.EntityType);
        Assert.AreEqual("C", third.EntityType);
    }

    [TestMethod]
    public void SendNotification_IsRead_DefaultsFalse()
    {
        // Act
        _service.SendNotification("Test", "1", EntityOperation.CREATE);
        var result = _service.ReceiveNotification();

        // Assert
        Assert.IsFalse(result.IsRead);
        Assert.IsNull(result.ReadAt);
    }
}

