using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using Microsoft.AspNetCore.Mvc;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using System;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class HomeControllerTests
{
    private SchoolContext _context;
    private HomeController _controller;

    [TestInitialize]
    public void TestInit()
    {
        TestHelpers.DrainNotificationQueue();
        _context = TestHelpers.CreateInMemoryContext();
        _controller = new HomeController(_context);
    }

    [TestCleanup]
    public void TestCleanup()
    {
        _controller?.Dispose();
        _context?.Dispose();
    }

    [TestMethod]
    public void Index_ReturnsViewResult()
    {
        // Act
        var result = _controller.Index();

        // Assert
        Assert.IsInstanceOfType<ViewResult>(result);
    }

    [TestMethod]
    public void About_ReturnsViewWithEnrollmentDateGroups()
    {
        // Arrange
        var date1 = new DateTime(2020, 9, 1);
        var date2 = new DateTime(2021, 9, 1);
        _context.Students.Add(new Student { ID = 1, LastName = "A", FirstMidName = "A", EnrollmentDate = date1 });
        _context.Students.Add(new Student { ID = 2, LastName = "B", FirstMidName = "B", EnrollmentDate = date1 });
        _context.Students.Add(new Student { ID = 3, LastName = "C", FirstMidName = "C", EnrollmentDate = date2 });
        _context.SaveChanges();

        // Act
        var result = _controller.About() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as List<EnrollmentDateGroup>;
        Assert.IsNotNull(model);
        Assert.AreEqual(2, model.Count);

        var group1 = model.First(g => g.EnrollmentDate == date1);
        Assert.AreEqual(2, group1.StudentCount);

        var group2 = model.First(g => g.EnrollmentDate == date2);
        Assert.AreEqual(1, group2.StudentCount);
    }

    [TestMethod]
    public void About_EmptyDatabase_ReturnsEmptyList()
    {
        // Act
        var result = _controller.About() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as List<EnrollmentDateGroup>;
        Assert.IsNotNull(model);
        Assert.AreEqual(0, model.Count);
    }

    [TestMethod]
    public void Contact_SetsViewBagMessage()
    {
        // Act
        var result = _controller.Contact() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Your contact page.", _controller.ViewData["Message"]);
    }

    [TestMethod]
    public void Error_ReturnsViewResult()
    {
        // Act
        var result = _controller.Error();

        // Assert
        Assert.IsInstanceOfType<ViewResult>(result);
    }

    [TestMethod]
    public void Unauthorized_SetsViewBagMessage()
    {
        // Act
        var result = _controller.Unauthorized() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("You don't have permission to access this resource.", _controller.ViewData["Message"]);
    }
}

