using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using System;
using System.Linq;
using System.Net;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class DepartmentsControllerTests
{
    private SchoolContext _context;
    private DepartmentsController _controller;

    [TestInitialize]
    public void TestInit()
    {
        TestHelpers.DrainNotificationQueue();
        _context = TestHelpers.CreateInMemoryContext();
        _controller = new DepartmentsController(_context);

        // Seed data
        var instructor = new Instructor
        {
            ID = 1,
            LastName = "Smith",
            FirstMidName = "John",
            HireDate = DateTime.Parse("2000-01-01")
        };
        _context.Instructors.Add(instructor);

        var dept = new Department
        {
            DepartmentID = 1,
            Name = "Engineering",
            Budget = 350000,
            StartDate = DateTime.Parse("2007-09-01"),
            InstructorID = 1
        };
        _context.Departments.Add(dept);
        _context.SaveChanges();
    }

    [TestCleanup]
    public void TestCleanup()
    {
        _controller?.Dispose();
        _context?.Dispose();
    }

    [TestMethod]
    public void Index_ReturnsViewWithDepartments()
    {
        // Act
        var result = _controller.Index() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as System.Collections.Generic.List<Department>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.Count);
        Assert.AreEqual("Engineering", model[0].Name);
    }

    [TestMethod]
    public void Details_WithValidId_ReturnsViewWithDepartment()
    {
        // Act
        var result = _controller.Details(1) as ViewResult;

        // Assert
