        var model = result.Model as Department;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.DepartmentID);
        Assert.AreEqual("Engineering", model.Name);
        Assert.AreEqual(350000m, model.Budget);
    }

    [TestMethod]
    public void Details_WithNullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Details(null) as StatusCodeResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
    }

