    public void Details_WithInvalidId_ReturnsNotFound()
    {
        // Act
        var result = _controller.Details(9999) as NotFoundResult;

        // Assert
        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void Create_Get_ReturnsView()
    {
        // Act
        var result = _controller.Create() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.IsNotNull(result.ViewData["InstructorID"]);
    }

    [TestMethod]
    public void Create_Post_ValidDepartment_RedirectsToIndex()
    {
        // Arrange
