        var result = _controller.Create(dept) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);

        // Verify saved to DB
        var saved = _context.Departments.FirstOrDefault(d => d.Name == "Mathematics");
        Assert.IsNotNull(saved);
        Assert.AreEqual(100000m, saved.Budget);
    }

    [TestMethod]
    public void Create_Post_InvalidModel_ReturnsView()
    {
        // Arrange
        var dept = new Department { Name = "X", Budget = 0, StartDate = DateTime.Now };
        _controller.ModelState.AddModelError("Name", "Required");

        // Act
        var result = _controller.Create(dept) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.IsNotNull(result.ViewData["InstructorID"]);
    }

