    {
        // Act
        var result = _controller.Edit(null) as StatusCodeResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
    }

    [TestMethod]
    public void Edit_Get_WithInvalidId_ReturnsNotFound()
    {
        // Act
        var result = _controller.Edit(9999) as NotFoundResult;

        // Assert
        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void Edit_Post_ValidDepartment_RedirectsToIndex()
    {
        // Arrange
        var dept = new Department
        {
            DepartmentID = 1,
            Name = "Updated Engineering",
            Budget = 400000,
            StartDate = DateTime.Parse("2007-09-01"),
            InstructorID = 1
        };

        // Act
        var result = _controller.Edit(dept) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
    }

    [TestMethod]
    public void Edit_Post_InvalidModel_ReturnsView()
    {
        // Arrange
        var dept = new Department { DepartmentID = 1, Name = "X" };
        _controller.ModelState.AddModelError("Name", "Required");

        // Act
        var result = _controller.Edit(dept) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.IsNotNull(result.ViewData["InstructorID"]);
    }

    [TestMethod]
    public void Delete_Get_WithValidId_ReturnsViewWithDepartment()
    {
        // Act
        var result = _controller.Delete(1) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Department;
        Assert.IsNotNull(model);
        Assert.AreEqual("Engineering", model.Name);
    }

    [TestMethod]
    public void Delete_Get_WithNullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Delete(null) as StatusCodeResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
    }

    [TestMethod]
    public void Delete_Get_WithInvalidId_ReturnsNotFound()
    {
        // Act
        var result = _controller.Delete(9999) as NotFoundResult;

        // Assert
        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void DeleteConfirmed_RemovesDepartmentAndRedirects()
    {
        // Act
        var result = _controller.DeleteConfirmed(1) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);

        // Verify removed from DB
        var deleted = _context.Departments.Find(1);
        Assert.IsNull(deleted);
    }
}

