using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using System;
using System.Collections.Generic;
using System.Linq;
using System.Net;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class InstructorsControllerTests
{
    private SchoolContext _context;
    private InstructorsController _controller;

    [TestInitialize]
    public void TestInit()
    {
        TestHelpers.DrainNotificationQueue();
        _context = TestHelpers.CreateInMemoryContext();
        _controller = new InstructorsController(_context);

        // Seed data
        var dept = new Department
        {
            DepartmentID = 1,
            Name = "Engineering",
            Budget = 350000,
            StartDate = DateTime.Parse("2007-09-01")
        };
        _context.Departments.Add(dept);

        var course = new Course
        {
            CourseID = 1050,
            Title = "Chemistry",
            Credits = 3,
            DepartmentID = 1,
            Enrollments = new List<Enrollment>()
        };
        _context.Courses.Add(course);

        var instructor = new Instructor
        {
            ID = 1,
            LastName = "Smith",
            FirstMidName = "John",
            HireDate = DateTime.Parse("2000-01-01"),
            CourseAssignments = new List<CourseAssignment>
            {
                new CourseAssignment { InstructorID = 1, CourseID = 1050 }
            },
            OfficeAssignment = new OfficeAssignment { InstructorID = 1, Location = "Room 101" }
        };
        _context.Instructors.Add(instructor);

        var instructor2 = new Instructor
        {
            ID = 2,
            LastName = "Jones",
            FirstMidName = "Jane",
            HireDate = DateTime.Parse("2005-06-15"),
            CourseAssignments = new List<CourseAssignment>()
        };
        _context.Instructors.Add(instructor2);

        _context.SaveChanges();
    }

    [TestCleanup]
    public void TestCleanup()
    {
        _controller?.Dispose();
        _context?.Dispose();
    }

    [TestMethod]
    public void Index_ReturnsViewWithInstructors()
    {
        // Act
        var result = _controller.Index(null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as ContosoUniversity.Models.SchoolViewModels.InstructorIndexData;
        Assert.IsNotNull(model);
        Assert.AreEqual(2, model.Instructors.Count());
    }

    [TestMethod]
    public void Index_WithInstructorId_LoadsCourses()
    {
        // Act
        var result = _controller.Index(1, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as ContosoUniversity.Models.SchoolViewModels.InstructorIndexData;
        Assert.IsNotNull(model);
        Assert.IsNotNull(model.Courses);
        Assert.AreEqual(1, model.Courses.Count());
        Assert.AreEqual("Chemistry", model.Courses.First().Title);
    }

    [TestMethod]
    public void Details_WithValidId_ReturnsViewWithInstructor()
    {
        // Act
        var result = _controller.Details(1) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Instructor;
        Assert.IsNotNull(model);
        Assert.AreEqual("Smith", model.LastName);
        Assert.AreEqual("John", model.FirstMidName);
    }

    [TestMethod]
    public void Details_WithNullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Details(null) as StatusCodeResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
    }

    [TestMethod]
    public void Details_WithInvalidId_ReturnsNotFound()
    {
        // Act
        var result = _controller.Details(9999) as NotFoundResult;

        // Assert
        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void Create_Get_ReturnsViewWithInstructor()
    {
        // Act
        var result = _controller.Create() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Instructor;
        Assert.IsNotNull(model);
        Assert.IsNotNull(model.CourseAssignments);
    }

    [TestMethod]
    public void Create_Post_ValidInstructor_RedirectsToIndex()
    {
        // Arrange
        var instructor = new Instructor
        {
            LastName = "NewInstructor",
            FirstMidName = "Test",
            HireDate = DateTime.Parse("2020-01-01")
        };

        // Act
        var result = _controller.Create(instructor, null) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);

        // Verify saved
        var saved = _context.Instructors.FirstOrDefault(i => i.LastName == "NewInstructor");
        Assert.IsNotNull(saved);
        Assert.AreEqual("Test", saved.FirstMidName);
    }

    [TestMethod]
    public void Create_Post_WithSelectedCourses_AssignsCourses()
    {
        // Arrange
        var instructor = new Instructor
        {
            LastName = "CourseInstructor",
            FirstMidName = "With",
            HireDate = DateTime.Parse("2020-01-01")
        };
        var selectedCourses = new[] { "1050" };

        // Act
        var result = _controller.Create(instructor, selectedCourses) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);

        var saved = _context.Instructors.FirstOrDefault(i => i.LastName == "CourseInstructor");
        Assert.IsNotNull(saved);
        Assert.AreEqual(1, saved.CourseAssignments.Count);
        Assert.AreEqual(1050, saved.CourseAssignments.First().CourseID);
    }

    [TestMethod]
    public void Create_Post_InvalidModel_ReturnsView()
    {
        // Arrange
        var instructor = new Instructor { LastName = "X", FirstMidName = "Y", HireDate = DateTime.Now };
        _controller.ModelState.AddModelError("LastName", "Required");

        // Act
        var result = _controller.Create(instructor, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void Delete_Get_WithValidId_ReturnsViewWithInstructor()
    {
        // Act
        var result = _controller.Delete(1) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Instructor;
        Assert.IsNotNull(model);
        Assert.AreEqual("Smith", model.LastName);
    }

    [TestMethod]
    public void Delete_Get_WithNullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Delete(null) as StatusCodeResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
    }

    [TestMethod]
    public void Delete_Get_WithInvalidId_ReturnsNotFound()
    {
        // Act
        var result = _controller.Delete(9999) as NotFoundResult;

        // Assert
        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void DeleteConfirmed_RemovesInstructorAndRedirects()
    {
        // Act
        var result = _controller.DeleteConfirmed(2) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);

        // Verify removed
        var deleted = _context.Instructors.Find(2);
        Assert.IsNull(deleted);
    }

    [TestMethod]
    public void DeleteConfirmed_ClearsDepartmentAdministrator()
    {
        // Arrange - assign instructor 1 as department administrator
        var dept = _context.Departments.Find(1);
        dept.InstructorID = 1;
        _context.SaveChanges();

        // Act
        var result = _controller.DeleteConfirmed(1) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);

        // Verify department InstructorID is cleared
        var updatedDept = _context.Departments.Find(1);
        Assert.IsNull(updatedDept.InstructorID);
    }
}

