using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Microsoft.AspNetCore.Mvc;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using System;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class NotificationsControllerTests
{
    private SchoolContext _context;
    private NotificationsController _controller;

    [TestInitialize]
    public void TestInit()
    {
        TestHelpers.DrainNotificationQueue();
        _context = TestHelpers.CreateInMemoryContext();
        _controller = new NotificationsController(_context);
    }

    [TestCleanup]
    public void TestCleanup()
    {
        _controller?.Dispose();
        _context?.Dispose();
    }

    [TestMethod]
    public void GetNotifications_EmptyQueue_ReturnsSuccessWithEmptyList()
    {
        // Act
        var result = _controller.GetNotifications();

        // Assert
        Assert.IsNotNull(result);
        Assert.IsNotNull(result.Value);

        var value = result.Value;
        var successProp = value.GetType().GetProperty("success");
        var countProp = value.GetType().GetProperty("count");

        Assert.IsNotNull(successProp);
        Assert.AreEqual(true, (bool)successProp.GetValue(value));
        Assert.AreEqual(0, (int)countProp.GetValue(value));
    }

    [TestMethod]
    public void GetNotifications_WithNotifications_ReturnsNotifications()
    {
        // Arrange - enqueue some notifications via the shared static queue
        var service = new NotificationService();
        service.SendNotification("Student", "1", "John Smith", EntityOperation.CREATE, "Admin");
        service.SendNotification("Course", "1050", "Chemistry", EntityOperation.UPDATE, "Admin");

        // Act
        var result = _controller.GetNotifications();

        // Assert
        Assert.IsNotNull(result);
        var value = result.Value;
        var successProp = value.GetType().GetProperty("success");
        var countProp = value.GetType().GetProperty("count");

        Assert.AreEqual(true, (bool)successProp.GetValue(value));
        Assert.AreEqual(2, (int)countProp.GetValue(value));
    }

    [TestMethod]
    public void GetNotifications_LimitsTo10()
    {
        // Arrange - enqueue more than 10 notifications
        var service = new NotificationService();
        for (int i = 0; i < 15; i++)
        {
            service.SendNotification("Entity", i.ToString(), EntityOperation.CREATE, "Admin");
        }

        // Act
        var result = _controller.GetNotifications();

        // Assert
        Assert.IsNotNull(result);
        var value = result.Value;
        var countProp = value.GetType().GetProperty("count");
        Assert.AreEqual(10, (int)countProp.GetValue(value));
    }

    [TestMethod]
    public void MarkAsRead_ReturnsSuccessJson()
    {
        // Act
        var result = _controller.MarkAsRead(1);

        // Assert
        Assert.IsNotNull(result);
        var value = result.Value;
        var successProp = value.GetType().GetProperty("success");
        Assert.AreEqual(true, (bool)successProp.GetValue(value));
    }

    [TestMethod]
    public void Index_ReturnsViewResult()
    {
        // Act
        var result = _controller.Index();

        // Assert
        Assert.IsInstanceOfType<ViewResult>(result);
    }
}

