    public void Initialize_AlreadySeeded_DoesNotDuplicate()
    {
        // Arrange
        var context = TestHelpers.CreateInMemoryContext();
        context.Students.Add(new Student
        {
            LastName = "Existing",
            FirstMidName = "Student",
            EnrollmentDate = DateTime.Parse("2020-01-01")
        });
        context.SaveChanges();

        // Act
        DbInitializer.Initialize(context);

        // Assert - should not add more students since there's already at least one
        Assert.AreEqual(1, context.Students.Count());
        Assert.AreEqual("Existing", context.Students.First().LastName);
    }
}

