using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using System;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests.Data;

[TestClass]
public sealed class SchoolContextTests
{
    [TestMethod]
    public void Context_CanBeCreatedWithInMemory()
    {
        // Act
        using var context = TestHelpers.CreateInMemoryContext();

        // Assert
        Assert.IsNotNull(context);
        Assert.IsNotNull(context.Courses);
        Assert.IsNotNull(context.Students);
        Assert.IsNotNull(context.Instructors);
        Assert.IsNotNull(context.Departments);
        Assert.IsNotNull(context.Enrollments);
        Assert.IsNotNull(context.OfficeAssignments);
        Assert.IsNotNull(context.CourseAssignments);
        Assert.IsNotNull(context.People);
        Assert.IsNotNull(context.Notifications);
    }

    [TestMethod]
    public void Context_CourseAssignment_HasCompositeKey()
    {
        // Arrange
        using var context = TestHelpers.CreateInMemoryContext();

        var instructor = new Instructor
        {
            ID = 1,
            LastName = "Smith",
            FirstMidName = "John",
            HireDate = DateTime.Parse("2000-01-01"),
            CourseAssignments = new List<CourseAssignment>()
        };
        context.Instructors.Add(instructor);

        var course = new Course
        {
            CourseID = 1050,
            Title = "Chemistry",
            Credits = 3,
            DepartmentID = 0
        };
        context.Courses.Add(course);
        context.SaveChanges();

        // Act
        var ca = new CourseAssignment { InstructorID = 1, CourseID = 1050 };
        context.CourseAssignments.Add(ca);
        context.SaveChanges();

        // Assert
        var found = context.CourseAssignments.Find(1050, 1);
        Assert.IsNotNull(found);
        Assert.AreEqual(1050, found.CourseID);
        Assert.AreEqual(1, found.InstructorID);
    }

    [TestMethod]
    public void Context_Student_StoresAndRetrievesCorrectly()
    {
        // Arrange
        using var context = TestHelpers.CreateInMemoryContext();
        var student = new Student
        {
            LastName = "TestStudent",
            FirstMidName = "First",
            EnrollmentDate = new DateTime(2020, 9, 1)
        };

        // Act
        context.Students.Add(student);
        context.SaveChanges();

        // Assert
        var retrieved = context.Students.First(s => s.LastName == "TestStudent");
        Assert.AreEqual("TestStudent", retrieved.LastName);
        Assert.AreEqual("First", retrieved.FirstMidName);
        Assert.AreEqual(new DateTime(2020, 9, 1), retrieved.EnrollmentDate);
    }

    [TestMethod]
    public void Context_Notification_StoresAndRetrievesCorrectly()
    {
        // Arrange
        using var context = TestHelpers.CreateInMemoryContext();
        var notification = new Notification
        {
            EntityType = "Student",
            EntityId = "1",
            Operation = "CREATE",
            Message = "New student created",
            CreatedAt = new DateTime(2024, 1, 15, 10, 0, 0),
            CreatedBy = "Admin",
            IsRead = false
        };

        // Act
        context.Notifications.Add(notification);
        context.SaveChanges();

        // Assert
        var retrieved = context.Notifications.First();
        Assert.AreEqual("Student", retrieved.EntityType);
        Assert.AreEqual("1", retrieved.EntityId);
        Assert.AreEqual("CREATE", retrieved.Operation);
        Assert.AreEqual("New student created", retrieved.Message);
        Assert.AreEqual("Admin", retrieved.CreatedBy);
        Assert.IsFalse(retrieved.IsRead);
    }

    [TestMethod]
    public void Context_Department_WithInstructor_Relationship()
    {
        // Arrange
        using var context = TestHelpers.CreateInMemoryContext();
        var instructor = new Instructor
        {
            ID = 10,
            LastName = "Dept",
            FirstMidName = "Admin",
            HireDate = DateTime.Parse("2000-01-01"),
            CourseAssignments = new List<CourseAssignment>()
        };
        context.Instructors.Add(instructor);

        var dept = new Department
        {
            DepartmentID = 1,
            Name = "Science",
            Budget = 100000,
            StartDate = DateTime.Parse("2007-09-01"),
            InstructorID = 10
        };
        context.Departments.Add(dept);
        context.SaveChanges();

        // Act
        var retrieved = context.Departments.Include(d => d.Administrator).First();

        // Assert
        Assert.AreEqual("Science", retrieved.Name);
        Assert.IsNotNull(retrieved.Administrator);
        Assert.AreEqual("Dept", retrieved.Administrator.LastName);
    }
}

